using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;

var builder = Host.CreateApplicationBuilder(args);

// Stdio transport uses stdout for JSON-RPC — all logging MUST go to stderr.
builder.Logging.AddConsole(options =>
    options.LogToStandardErrorThreshold = LogLevel.Trace);

builder.Services.AddHttpClient("api", client =>
{
    client.BaseAddress = new Uri("https://jsonplaceholder.typicode.com");
});

builder.Services
    .AddMcpServer()
    .WithStdioServerTransport()
    .WithToolsFromAssembly();

await builder.Build().RunAsync();

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

/// <summary>
/// MCP tools that wrap a REST API via HttpClient.
/// Non-static class: the SDK creates an instance per invocation,
/// injecting constructor parameters from the DI container.
/// </summary>
[McpServerToolType]
public class ApiTools(IHttpClientFactory httpClientFactory, ILogger<ApiTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool(ReadOnly = true), Description("Get a post by its ID.")]
    public async Task<string> GetPost(
        [Description("The numeric post ID (1-100).")] int id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching post {Id}", id);
        var client = httpClientFactory.CreateClient("api");
        var json = await client.GetStringAsync($"/posts/{id}", cancellationToken);
        return json;
    }

    [McpServerTool(ReadOnly = true), Description("List all posts, optionally filtered by user ID.")]
    public async Task<string> ListPosts(
        [Description("Filter posts by this user ID. Omit to return all posts.")] int? userId = null,
        CancellationToken cancellationToken = default)
    {
        var client = httpClientFactory.CreateClient("api");
        var url = userId.HasValue ? $"/posts?userId={userId}" : "/posts";
        var json = await client.GetStringAsync(url, cancellationToken);
        return json;
    }

    [McpServerTool, Description("Create a new post.")]
    public async Task<string> CreatePost(
        [Description("Title of the post.")] string title,
        [Description("Body content of the post.")] string body,
        [Description("Author's user ID.")] int userId,
        CancellationToken cancellationToken = default)
    {
        var client = httpClientFactory.CreateClient("api");
        var payload = new { title, body, userId };
        var response = await client.PostAsJsonAsync("/posts", payload, cancellationToken);
        response.EnsureSuccessStatusCode();

        var result = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken);
        return JsonSerializer.Serialize(result, JsonOptions);
    }
}

